// src/model.ts
import { z } from "zod";
var reasoningEfforts = ["low", "medium", "high"];
var reasoningEffortsSchema = z.enum(reasoningEfforts);
var reasoningEffortWithMinimalSchema = z.union([reasoningEffortsSchema, z.literal("minimal")]);
var reasoningEffortsExtended = ["none", "minimal", "low", "medium", "high", "xhigh"];
var reasoningEffortExtendedSchema = z.enum(reasoningEffortsExtended);
var reasoningEffortSettingValues = ["disable", "none", "minimal", "low", "medium", "high", "xhigh"];
var reasoningEffortSettingSchema = z.enum(reasoningEffortSettingValues);
var verbosityLevels = ["low", "medium", "high"];
var verbosityLevelsSchema = z.enum(verbosityLevels);
var serviceTiers = ["default", "flex", "priority"];
var serviceTierSchema = z.enum(serviceTiers);
var modelParameters = ["max_tokens", "temperature", "reasoning", "include_reasoning"];
var modelParametersSchema = z.enum(modelParameters);
var isModelParameter = (value) => modelParameters.includes(value);
var modelInfoSchema = z.object({
  maxTokens: z.number().nullish(),
  maxThinkingTokens: z.number().nullish(),
  contextWindow: z.number(),
  supportsImages: z.boolean().optional(),
  supportsPromptCache: z.boolean(),
  // Optional default prompt cache retention policy for providers that support it.
  // When set to "24h", extended prompt caching will be requested; when omitted
  // or set to "in_memory", the default in‑memory cache is used.
  promptCacheRetention: z.enum(["in_memory", "24h"]).optional(),
  // Capability flag to indicate whether the model supports an output verbosity parameter
  supportsVerbosity: z.boolean().optional(),
  supportsReasoningBudget: z.boolean().optional(),
  // Capability flag to indicate whether the model supports simple on/off binary reasoning
  supportsReasoningBinary: z.boolean().optional(),
  // Capability flag to indicate whether the model supports temperature parameter
  supportsTemperature: z.boolean().optional(),
  defaultTemperature: z.number().optional(),
  requiredReasoningBudget: z.boolean().optional(),
  supportsReasoningEffort: z.union([z.boolean(), z.array(z.enum(["disable", "none", "minimal", "low", "medium", "high", "xhigh"]))]).optional(),
  requiredReasoningEffort: z.boolean().optional(),
  preserveReasoning: z.boolean().optional(),
  supportedParameters: z.array(modelParametersSchema).optional(),
  inputPrice: z.number().optional(),
  outputPrice: z.number().optional(),
  cacheWritesPrice: z.number().optional(),
  cacheReadsPrice: z.number().optional(),
  description: z.string().optional(),
  // Default effort value for models that support reasoning effort
  reasoningEffort: reasoningEffortExtendedSchema.optional(),
  minTokensPerCachePoint: z.number().optional(),
  maxCachePoints: z.number().optional(),
  cachableFields: z.array(z.string()).optional(),
  // Flag to indicate if the model is deprecated and should not be used
  deprecated: z.boolean().optional(),
  // Flag to indicate if the model should hide vendor/company identity in responses
  isStealthModel: z.boolean().optional(),
  // Flag to indicate if the model is free (no cost)
  isFree: z.boolean().optional(),
  // Exclude specific native tools from being available (only applies to native protocol)
  // These tools will be removed from the set of tools available to the model
  excludedTools: z.array(z.string()).optional(),
  // Include specific native tools (only applies to native protocol)
  // These tools will be added if they belong to an allowed group in the current mode
  // Cannot force-add tools from groups the mode doesn't allow
  includedTools: z.array(z.string()).optional(),
  /**
   * Service tiers with pricing information.
   * Each tier can have a name (for OpenAI service tiers) and pricing overrides.
   * The top-level input/output/cache* fields represent the default/standard tier.
   */
  tiers: z.array(
    z.object({
      name: serviceTierSchema.optional(),
      // Service tier name (flex, priority, etc.)
      contextWindow: z.number(),
      inputPrice: z.number().optional(),
      outputPrice: z.number().optional(),
      cacheWritesPrice: z.number().optional(),
      cacheReadsPrice: z.number().optional()
    })
  ).optional()
});

// src/codebase-index.ts
import { z as z2 } from "zod";
var CODEBASE_INDEX_DEFAULTS = {
  MIN_SEARCH_RESULTS: 10,
  MAX_SEARCH_RESULTS: 200,
  DEFAULT_SEARCH_RESULTS: 50,
  SEARCH_RESULTS_STEP: 10,
  MIN_SEARCH_SCORE: 0,
  MAX_SEARCH_SCORE: 1,
  DEFAULT_SEARCH_MIN_SCORE: 0.4,
  SEARCH_SCORE_STEP: 0.05
};
var codebaseIndexConfigSchema = z2.object({
  codebaseIndexEnabled: z2.boolean().optional(),
  codebaseIndexQdrantUrl: z2.string().optional(),
  codebaseIndexEmbedderProvider: z2.enum([
    "openai",
    "ollama",
    "openai-compatible",
    "gemini",
    "mistral",
    "vercel-ai-gateway",
    "bedrock",
    "openrouter"
  ]).optional(),
  codebaseIndexEmbedderBaseUrl: z2.string().optional(),
  codebaseIndexEmbedderModelId: z2.string().optional(),
  codebaseIndexEmbedderModelDimension: z2.number().optional(),
  codebaseIndexSearchMinScore: z2.number().min(0).max(1).optional(),
  codebaseIndexSearchMaxResults: z2.number().min(CODEBASE_INDEX_DEFAULTS.MIN_SEARCH_RESULTS).max(CODEBASE_INDEX_DEFAULTS.MAX_SEARCH_RESULTS).optional(),
  // OpenAI Compatible specific fields
  codebaseIndexOpenAiCompatibleBaseUrl: z2.string().optional(),
  codebaseIndexOpenAiCompatibleModelDimension: z2.number().optional(),
  // Bedrock specific fields
  codebaseIndexBedrockRegion: z2.string().optional(),
  codebaseIndexBedrockProfile: z2.string().optional(),
  // OpenRouter specific fields
  codebaseIndexOpenRouterSpecificProvider: z2.string().optional()
});
var codebaseIndexModelsSchema = z2.object({
  openai: z2.record(z2.string(), z2.object({ dimension: z2.number() })).optional(),
  ollama: z2.record(z2.string(), z2.object({ dimension: z2.number() })).optional(),
  "openai-compatible": z2.record(z2.string(), z2.object({ dimension: z2.number() })).optional(),
  gemini: z2.record(z2.string(), z2.object({ dimension: z2.number() })).optional(),
  mistral: z2.record(z2.string(), z2.object({ dimension: z2.number() })).optional(),
  "vercel-ai-gateway": z2.record(z2.string(), z2.object({ dimension: z2.number() })).optional(),
  openrouter: z2.record(z2.string(), z2.object({ dimension: z2.number() })).optional(),
  bedrock: z2.record(z2.string(), z2.object({ dimension: z2.number() })).optional()
});
var codebaseIndexProviderSchema = z2.object({
  codeIndexOpenAiKey: z2.string().optional(),
  codeIndexQdrantApiKey: z2.string().optional(),
  codebaseIndexOpenAiCompatibleBaseUrl: z2.string().optional(),
  codebaseIndexOpenAiCompatibleApiKey: z2.string().optional(),
  codebaseIndexOpenAiCompatibleModelDimension: z2.number().optional(),
  codebaseIndexGeminiApiKey: z2.string().optional(),
  codebaseIndexMistralApiKey: z2.string().optional(),
  codebaseIndexVercelAiGatewayApiKey: z2.string().optional(),
  codebaseIndexOpenRouterApiKey: z2.string().optional()
});

